function [scanX,scanXList,imgSize] = fScanDirListV03(scanDir,inScn,diagN)%% help for fScanDirListV03%% Searches directory, returns scan list with log and images within%% [scanX,scanXList,imgSize] = fScanDirListV03(scanDir,inScn,diagN)%% Input% scanDir: scan directory, usually '../scans'% inScan: input scan to go through (not necessary to exist)% diagN: diagnostic file name, like 'OTR'%% Output% scanX: array of scan numbers% scnXList: cell array of the name of the directories% imgSz: image size, height-width for allocation use%% Written by Kei Nakamura% Created on Monday, June 1st 2009.%% Modified on Friday, June 11th 2010.% ver.2: update%% Modified on Thursday, April 26th 2012.% update, mod for staging%% main bodyjj = 1;     % index for output scanscanXList{1} = 'null';           % in case scan doesn't exist, to retun nullscanX(1) = -1;                   % nullfor ii=1:numel(inScn);  % input scan loop    scanNS = fGet3NmbStringV01(inScn(ii));  % 3 digit scan number string    scanXDir = [scanDir,'/Scan',scanNS];       % scan directory    diagDir = [scanXDir,'/',diagN];   % diag directory    logEx = exist([scanXDir,'/ScanDataScan',scanNS,'.txt'],'file');    % log exist        imgList = dir([diagDir,'/Scan',scanNS,'_',diagN,'_','*.png']);    % list of image    imgEx = abs(sign(numel(imgList)));      % image exist (more than 1)    imgInf = imfinfo([diagDir,'/',imgList(1).name]);    imgSize(1) = imgInf.Height;   % image row number    imgSize(2) = imgInf.Width;    % image clm number        if logEx&&imgEx        scanX(jj) = inScn(ii);           % scan number        scanXList{jj} = ['Scan',scanNS];    % scan directory name        jj = jj + 1;    endend% infrm = dir([scanDir,'/Scan*']);         % information for Scan* file% nmbInScn = max(size(inScn));  % number of input scan% % ii = 1;     % index for info% jj = 1;     % index for inScn% kk = 1;     % index for outScn% scanXDir{1} = 'null';           % in case scan doesn't exist, to retun null% scanX(1) = -1;                   % null% % while jj<=nmbInScn          % go through all inScn   %     name = infrm(ii).name;  % directory name%     logName = ['ScanData',name,'.txt'];%     logPath = [roodDir,'/',name,'/',logName];   % full path for log file%     scnNmb = str2double(name(5:end));  % scan number%     while inScn(jj)<scnNmb  % input scan is smaller, go next inScn%         jj = jj + 1;%     end        %     if inScn(jj)==scnNmb && infrm(ii).isdir && exist(logPath)%         % if file is directory, and =input scan, and log exist%         scanXDir{kk} = name;%         scanX(kk) = scnNmb;            % output scan (exist and input)%         kk = kk+1;%         jj = jj+1;%     end%     ii = ii+1;% end
